package v1alpha1

import (
	corev1 "k8s.io/api/core/v1"
	metav1 "k8s.io/apimachinery/pkg/apis/meta/v1"
)

const (
	CodeInterpreterKind     = "CodeInterpreter"
	CodeInterpreterListKind = "CodeInterpreterList"
)

var (
	CodeInterpreterGroupKind        = GroupVersion.WithKind("CodeInterpreter")
	CodeInterpreterGroupVersionKind = GroupVersion.WithKind("CodeInterpreter")
)

type CodeInterpreter struct {
	metav1.TypeMeta   `json:",inline"`
	metav1.ObjectMeta `json:"metadata,omitempty"`

class AgentCubeError(Exception):
    """Base exception for AgentCube SDK."""
    pass


class CommandExecutionError(AgentCubeError):
    """Raised when command execution fails with non-zero exit code."""

    def __init__(self, exit_code: int, stderr: str, command: list):
        self.exit_code = exit_code
        self.stderr = stderr
        self.command = command
        super().__init__(f"Command {command} failed with exit code {exit_code}: {stderr}")


class SessionError(AgentCubeError):
    """Raised when session operations fail."""
    pass

