package picod

import (
	"context"
	"crypto/rsa"
	"encoding/base64"
	"encoding/json"
	"fmt"
	"io"
	"mime"
	"net/http"
	"os"
	"os/exec"
	"path/filepath"
	"strconv"
	"strings"
	"time"

	"github.com/gin-gonic/gin"
	"github.com/golang-jwt/jwt/v5"
)

const (
	DefaultTimeout      = 60 * time.Second
	TimeoutExitCode     = 124
	DefaultPort         = "8080"
	MaxBodySize   int64 = 10 * 1024 * 1024
)

type Config struct {
	Port           string
	Workspace      string
	PublicKeyPEM   string
	MaxBodySize    int64
	DefaultTimeout time.Duration
}

type Server struct {
	config     *Config
	router     *gin.Engine
	httpServer *http.Server
	publicKey  *rsa.PublicKey
	startTime  time.Time
	workspace  string
}

type ExecuteRequest struct {
	Command     []string          `json:"command"`
	Timeout     string            `json:"timeout"`
	WorkingDir  string            `json:"working_dir"`
	Env         map[string]string `json:"env"`
}

type ExecuteResponse struct {
	Stdout    string  `json:"stdout"`
	Stderr    string  `json:"stderr"`
	ExitCode  int     `json:"exit_code"`
	Duration  float64 `json:"duration"`
	StartTime string  `json:"start_time"`
	EndTime   string  `json:"end_time"`
}

type UploadFileRequest struct {
	Path    string `json:"path"`
	Content string `json:"content"`
	Mode    string `json:"mode"`
}

type FileInfo struct {
	Path     string `json:"path"`
	Size     int64  `json:"size"`
	Modified string `json:"modified"`
	Mode     string `json:"mode"`
	IsDir    bool   `json:"is_dir"`
}

type ListFilesResponse struct {
	Files []FileInfo `json:"files"`
}

type ErrorResponse struct {
	Error string `json:"error"`
	Code  int    `json:"code"`
}

type HealthResponse struct {
	Status  string `json:"status"`
	Service string `json:"service"`
	Version string `json:"version"`
	Uptime  string `json:"uptime"`
}

func NewServer(cfg *Config) (*Server, error) {
	if cfg.Port == "" {
		cfg.Port = DefaultPort
	}
	if cfg.MaxBodySize == 0 {
		cfg.MaxBodySize = MaxBodySize
	}
	if cfg.DefaultTimeout == 0 {
		cfg.DefaultTimeout = DefaultTimeout
	}

	workspace := cfg.Workspace
	if workspace == "" {
		var err error
		workspace, err = os.Getwd()
		if err != nil {
			return nil, fmt.Errorf("failed to get working directory: %w", err)
		}
	}

	absWorkspace, err := filepath.Abs(workspace)
	if err != nil {
		return nil, fmt.Errorf("failed to resolve workspace path: %w", err)
	}

	s := &Server{
		config:    cfg,
		workspace: absWorkspace,
		startTime: time.Now(),
	}

	if cfg.PublicKeyPEM != "" {
		pubKey, err := parseRSAPublicKeyFromPEM(cfg.PublicKeyPEM)
		if err != nil {
			return nil, fmt.Errorf("failed to parse public key: %w", err)
		}
		s.publicKey = pubKey
	} else {
		return nil, fmt.Errorf("PICOD_AUTH_PUBLIC_KEY is required")
	}

	gin.SetMode(gin.ReleaseMode)
	s.router = gin.New()
	s.router.Use(gin.Logger(), gin.Recovery())

	s.setupRoutes()

	return s, nil
}

func parseRSAPublicKeyFromPEM(pemStr string) (*rsa.PublicKey, error) {
	block, _ := pem.Decode([]byte(pemStr))
	if block == nil {
		return nil, fmt.Errorf("failed to parse PEM block")
	}

	pub, err := jwt.ParseRSAPublicKeyFromPEM([]byte(pemStr))
	if err != nil {
		return nil, err
	}

	return pub, nil
}

func (s *Server) setupRoutes() {
	s.router.GET("/health", s.handleHealth)

	api := s.router.Group("/api")
	api.Use(s.authMiddleware())
	api.POST("/execute", s.handleExecute)
	api.POST("/files", s.handleFileUpload)
	api.GET("/files", s.handleFileList)
	api.GET("/files/*path", s.handleFileDownload)
}

func (s *Server) authMiddleware() gin.HandlerFunc {
	return func(c *gin.Context) {
		authHeader := c.GetHeader("Authorization")
		if authHeader == "" {
			c.JSON(http.StatusUnauthorized, ErrorResponse{
				Error: "Missing authorization header",
				Code:  http.StatusUnauthorized,
			})
			c.Abort()
			return
		}

		parts := strings.SplitN(authHeader, " ", 2)
		if len(parts) != 2 || parts[0] != "Bearer" {
			c.JSON(http.StatusUnauthorized, ErrorResponse{
				Error: "Invalid authorization header format",
				Code:  http.StatusUnauthorized,
			})
			c.Abort()
			return
		}

		tokenString := parts[1]
		token, err := jwt.Parse(tokenString, func(token *jwt.Token) (interface{}, error) {
			if _, ok := token.Method.(*jwt.SigningMethodRSA); !ok {
				return nil, fmt.Errorf("unexpected signing method: %v", token.Header["alg"])
			}
			return s.publicKey, nil
		}, jwt.WithExpirationRequired(), jwt.WithIssuedAt(), jwt.WithLeeway(time.Minute))

		if err != nil {
			c.JSON(http.StatusUnauthorized, ErrorResponse{
				Error:  "Invalid token",
				Code:   http.StatusUnauthorized,
				Detail: err.Error(),
			})
			c.Abort()
			return
		}

		if !token.Valid {
			c.JSON(http.StatusUnauthorized, ErrorResponse{
				Error: "Invalid token",
				Code:  http.StatusUnauthorized,
			})
			c.Abort()
			return
		}

		c.Request.Body = http.MaxBytesReader(c.Writer, c.Request.Body, s.config.MaxBodySize)
		c.Next()
	}
}

func (s *Server) handleHealth(c *gin.Context) {
	uptime := time.Since(s.startTime)
	c.JSON(http.StatusOK, HealthResponse{
		Status:  "ok",
		Service: "PicoD",
		Version: "0.0.1",
		Uptime:  uptime.String(),
	})
}

func (s *Server) handleExecute(c *gin.Context) {
	var req ExecuteRequest
	if err := c.ShouldBindJSON(&req); err != nil {
		c.JSON(http.StatusBadRequest, ErrorResponse{
			Error: err.Error(),
			Code:  http.StatusBadRequest,
		})
		return
	}

	if len(req.Command) == 0 {
		c.JSON(http.StatusBadRequest, ErrorResponse{
			Error: "command cannot be empty",
			Code:  http.StatusBadRequest,
		})
		return
	}

	timeout := s.config.DefaultTimeout
	if req.Timeout != "" {
		parsed, err := time.ParseDuration(req.Timeout)
		if err != nil {
			c.JSON(http.StatusBadRequest, ErrorResponse{
				Error: "invalid timeout format",
				Code:  http.StatusBadRequest,
			})
			return
		}
		timeout = parsed
	}

	workingDir := s.workspace
	if req.WorkingDir != "" {
		sanitized, err := s.sanitizePath(req.WorkingDir)
		if err != nil {
			c.JSON(http.StatusBadRequest, ErrorResponse{
				Error: fmt.Sprintf("Invalid working directory: %v", err),
				Code:  http.StatusBadRequest,
			})
			return
		}
		workingDir = sanitized
	}

	ctx, cancel := context.WithTimeout(c.Request.Context(), timeout)
	defer cancel()

	cmd := exec.CommandContext(ctx, req.Command[0], req.Command[1:]...)
	cmd.Dir = workingDir
