func (s *Server) sanitizePath(path string) (string, error) {
	if path == "" {
		return s.workspace, nil
	}

	absPath := filepath.Clean(filepath.Join(s.workspace, path))
	if !strings.HasPrefix(absPath, s.workspace) {
		return "", fmt.Errorf("path escapes workspace")
	}

	return absPath, nil
}

func (s *Server) respondFileInfo(c *gin.Context, absPath string) {
	info, err := os.Stat(absPath)
	if err != nil {
		c.JSON(http.StatusInternalServerError, ErrorResponse{
