		return
	}

	if req.Path == "" {
		c.JSON(http.StatusBadRequest, ErrorResponse{
			Error: "path is required",
			Code:  http.StatusBadRequest,
		})
		return
	}

	if req.Content == "" {
		c.JSON(http.StatusBadRequest, ErrorResponse{
			Error: "content is required",
			Code:  http.StatusBadRequest,
		})
		return
	}

	content, err := base64.StdEncoding.DecodeString(req.Content)
	if err != nil {
		c.JSON(http.StatusBadRequest, ErrorResponse{
			Error: "invalid base64 content",
			Code:  http.StatusBadRequest,
		})
		return
	}

	sanitizedPath, err := s.sanitizePath(req.Path)
	if err != nil {
		c.JSON(http.StatusBadRequest, ErrorResponse{
			Error: err.Error(),
			Code:  http.StatusBadRequest,
		})
		return
	}

	if err := os.MkdirAll(filepath.Dir(sanitizedPath), 0755); err != nil {
		c.JSON(http.StatusInternalServerError, ErrorResponse{
			Error: fmt.Sprintf("failed to create directories: %v", err),
			Code:  http.StatusInternalServerError,
		})
		return
	}

	mode := parseFileMode(req.Mode, 0644)
	if err := os.WriteFile(sanitizedPath, content, mode); err != nil {
		c.JSON(http.StatusInternalServerError, ErrorResponse{
			Error: fmt.Sprintf("failed to write file: %v", err),
			Code:  http.StatusInternalServerError,
		})
		return
	}

	s.respondFileInfo(c, sanitizedPath)
}

func (s *Server) handleMultipartUpload(c *gin.Context) {
	path := c.PostForm("path")
	if path == "" {
		c.JSON(http.StatusBadRequest, ErrorResponse{
			Error: "path is required",
			Code:  http.StatusBadRequest,
		})
		return
	}

	file, _, err := c.Request.FormFile("file")
	if err != nil {
		c.JSON(http.StatusBadRequest, ErrorResponse{
			Error: "file is required",
			Code:  http.StatusBadRequest,
		})
		return
	}
	defer file.Close()

	sanitizedPath, err := s.sanitizePath(path)
	if err != nil {
		c.JSON(http.StatusBadRequest, ErrorResponse{
			Error: err.Error(),
			Code:  http.StatusBadRequest,
		})
		return
	}

	if err := os.MkdirAll(filepath.Dir(sanitizedPath), 0755); err != nil {
		c.JSON(http.StatusInternalServerError, ErrorResponse{
			Error: fmt.Sprintf("failed to create directories: %v", err),
			Code:  http.StatusInternalServerError,
		})
		return
	}

	dst, err := os.Create(sanitizedPath)
	if err != nil {
		c.JSON(http.StatusInternalServerError, ErrorResponse{
			Error: fmt.Sprintf("failed to create file: %v", err),
			Code:  http.StatusInternalServerError,
		})
		return
	}
	defer dst.Close()

	if _, err := io.Copy(dst, file); err != nil {
		c.JSON(http.StatusInternalServerError, ErrorResponse{
			Error: fmt.Sprintf("failed to write file: %v", err),
			Code:  http.StatusInternalServerError,
		})
		return
	}

	modeStr := c.PostForm("mode")
	mode := parseFileMode(modeStr, 0644)
	if err := os.Chmod(sanitizedPath, mode); err != nil {
		c.JSON(http.StatusInternalServerError, ErrorResponse{
			Error: fmt.Sprintf("failed to set file mode: %v", err),
			Code:  http.StatusInternalServerError,
		})
		return
	}

	s.respondFileInfo(c, sanitizedPath)
}

func (s *Server) handleFileList(c *gin.Context) {
	path := c.Query("path")
	if path == "" {
		c.JSON(http.StatusBadRequest, ErrorResponse{
			Error: "Missing 'path' query parameter",
			Code:  http.StatusBadRequest,
		})
		return
	}

	sanitizedPath, err := s.sanitizePath(path)
	if err != nil {
		c.JSON(http.StatusBadRequest, ErrorResponse{
			Error: err.Error(),
			Code:  http.StatusBadRequest,
		})
		return
	}

	entries, err := os.ReadDir(sanitizedPath)
	if err != nil {
		if os.IsNotExist(err) {
			c.JSON(http.StatusNotFound, ErrorResponse{
				Error: "Directory not found",
				Code:  http.StatusNotFound,
			})
			return
		}
		c.JSON(http.StatusInternalServerError, ErrorResponse{
			Error: err.Error(),
			Code:  http.StatusInternalServerError,
		})
		return
	}

	var files []FileInfo
	for _, entry := range entries {
		info, err := entry.Info()
		if err != nil {
			continue
		}

		relPath, _ := filepath.Rel(s.workspace, filepath.Join(sanitizedPath, entry.Name()))
		files = append(files, FileInfo{
			Path:     relPath,
			Size:     info.Size(),
			Modified: info.ModTime().UTC().Format(time.RFC3339),
			Mode:     info.Mode().String(),
			IsDir:    entry.IsDir(),
		})
	}

	c.JSON(http.StatusOK, ListFilesResponse{Files: files})
}

func (s *Server) handleFileDownload(c *gin.Context) {
	path := c.Param("path")
	if path == "" {
		c.JSON(http.StatusBadRequest, ErrorResponse{
			Error: "path is required",
			Code:  http.StatusBadRequest,
		})
		return
	}

	sanitizedPath, err := s.sanitizePath(path)
	if err != nil {
		c.JSON(http.StatusBadRequest, ErrorResponse{
			Error: err.Error(),
			Code:  http.StatusBadRequest,
		})
		return
	}

	info, err := os.Stat(sanitizedPath)
	if err != nil {
		if os.IsNotExist(err) {
			c.JSON(http.StatusNotFound, ErrorResponse{
				Error: "File not found",
				Code:  http.StatusNotFound,
			})
			return
		}
		c.JSON(http.StatusInternalServerError, ErrorResponse{
			Error: err.Error(),
			Code:  http.StatusInternalServerError,
		})
		return
	}

	if info.IsDir() {
		c.JSON(http.StatusBadRequest, ErrorResponse{
			Error: "Path is a directory, not a file",
			Code:  http.StatusBadRequest,
		})
		return
	}

	contentType := mime.TypeByExtension(filepath.Ext(sanitizedPath))
	if contentType == "" {
		contentType = "application/octet-stream"
	}

	c.Header("Content-Description", "File Transfer")
	c.Header("Content-Transfer-Encoding", "binary")
	c.Header("Content-Disposition", fmt.Sprintf("attachment; filename=%q", filepath.Base(sanitizedPath)))
	c.Header("Content-Type", contentType)
	c.File(sanitizedPath)
}

func (s *Server) sanitizePath(path string) (string, error) {
	if path == "" {
		return s.workspace, nil
	}

	absPath := filepath.Clean(filepath.Join(s.workspace, path))
	if !strings.HasPrefix(absPath, s.workspace) {
		return "", fmt.Errorf("path escapes workspace")
	}

	return absPath, nil
}

func (s *Server) respondFileInfo(c *gin.Context, absPath string) {
	info, err := os.Stat(absPath)
	if err != nil {
		c.JSON(http.StatusInternalServerError, ErrorResponse{
			Error: fmt.Sprintf("failed to stat file: %v", err),
			Code:  http.StatusInternalServerError,
		})
		return
	}

	relPath, _ := filepath.Rel(s.workspace, absPath)
	c.JSON(http.StatusOK, FileInfo{
		Path:     relPath,
		Size:     info.Size(),
		Modified: info.ModTime().UTC().Format(time.RFC3339),
		Mode:     info.Mode().String(),
		IsDir:    info.IsDir(),
	})
}

func parseFileMode(modeStr string, defaultMode os.FileMode) os.FileMode {
	if modeStr == "" {
		return defaultMode
	}
	mode, err := strconv.ParseUint(modeStr, 8, 32)
	if err != nil || mode > 0777 {
		return defaultMode
	}
	return os.FileMode(mode)
}

func (s *Server) Start(ctx context.Context) error {
	addr := ":" + s.config.Port
	s.httpServer = &http.Server{
		Addr:              addr,
		Handler:           s.router,
		ReadHeaderTimeout: 10 * time.Second,
	}

	return s.httpServer.ListenAndServe()
}

func (s *Server) Shutdown(ctx context.Context) error {
	if s.httpServer != nil {
		return s.httpServer.Shutdown(ctx)
	}
	return nil
}

