package main

import (
	"context"
	"flag"
	"fmt"
	"net/http"
	"os"
	"os/signal"
	"syscall"

	"github.com/volcano-sh/agentcube/pkg/picod"
)

func main() {
	port := flag.String("port", "8080", "HTTP port")
	workspace := flag.String("workspace", "", "Workspace directory")
	publicKey := flag.String("public-key", "", "RSA public key PEM (or PICOD_AUTH_PUBLIC_KEY env)")
	flag.Parse()

	pubKeyPEM := *publicKey
	if pubKeyPEM == "" {
		pubKeyPEM = os.Getenv("PICOD_AUTH_PUBLIC_KEY")
	}

	cfg := &picod.Config{
		Port:         *port,
		Workspace:    *workspace,
		PublicKeyPEM: pubKeyPEM,
	}

	server, err := picod.NewServer(cfg)
	if err != nil {
		fmt.Fprintf(os.Stderr, "Failed to create server: %v\n", err)
		os.Exit(1)
	}

	ctx, cancel := context.WithCancel(context.Background())
	defer cancel()

	sigCh := make(chan os.Signal, 1)
	signal.Notify(sigCh, syscall.SIGINT, syscall.SIGTERM)

	go func() {
		<-sigCh
		fmt.Println("Shutting down...")
		if err := server.Shutdown(ctx); err != nil {
			fmt.Fprintf(os.Stderr, "Shutdown error: %v\n", err)
		}
		cancel()
	}()

	fmt.Printf("Starting PicoD on :%s\n", *port)
	if err := server.Start(ctx); err != nil && err != http.ErrServerClosed {
		fmt.Fprintf(os.Stderr, "Server error: %v\n", err)
		os.Exit(1)
	}
}

package router

import (
	"context"
	"crypto/rand"
	"crypto/rsa"
	"crypto/x509"
	"encoding/pem"
	"errors"
	"fmt"
	"net/http"
	"net/http/httputil"
	"net/url"
	"os"
	"strings"
	"sync"
	"time"

	"github.com/gin-gonic/gin"
	"github.com/golang-jwt/jwt/v5"
	"github.com/volcano-sh/agentcube/pkg/common/types"
	"github.com/volcano-sh/agentcube/pkg/store"
)

const (
	SessionHeader = "x-agentcube-session-id"
)

type Config struct {
	Port                 string
	WorkloadManagerURL   string
	MaxConcurrentRequests int
	EnableTLS            bool
	TLSCert              string
	TLSKey               string
}

type Server struct {
	config         *Config
	router         *gin.Engine
	httpServer     *http.Server
	sessionManager *SessionManager
	jwtManager     *JWTManager
	transport      *http.Transport
	semaphore      chan struct{}
}

type SessionManager struct {
	workloadManagerURL string
	authToken          string
	httpClient         *http.Client
	store              store.Store
}

type JWTManager struct {
	privateKey *rsa.PrivateKey
	publicKey  *rsa.PublicKey
	mu         sync.RWMutex
}

func NewServer(cfg *Config) (*Server, error) {
	if cfg.Port == "" {
		cfg.Port = "8080"
	}
	if cfg.MaxConcurrentRequests <= 0 {
		cfg.MaxConcurrentRequests = 1000
	}

	workloadManagerURL := cfg.WorkloadManagerURL
	if workloadManagerURL == "" {
		workloadManagerURL = os.Getenv("WORKLOAD_MANAGER_URL")
	}
	if workloadManagerURL == "" {
		return nil, errors.New("WORKLOAD_MANAGER_URL environment variable is not set")
	}

	sm, err := NewSessionManager(workloadManagerURL)
	if err != nil {
		return nil, err
	}

	jwtMgr, err := NewJWTManager()
	if err != nil {
		return nil, err
	}

	s := &Server{
		config:         cfg,
		sessionManager: sm,
		jwtManager:     jwtMgr,
		transport:      &http.Transport{},
		semaphore:      make(chan struct{}, cfg.MaxConcurrentRequests),
	}

	gin.SetMode(gin.ReleaseMode)
	s.router = gin.New()
	s.router.Use(gin.Logger(), gin.Recovery())

	s.setupRoutes()

	return s, nil
}

func NewSessionManager(workloadManagerURL string) (*SessionManager, error) {
	authToken := ""
	tokenPath := "/var/run/secrets/kubernetes.io/serviceaccount/token"
	if data, err := os.ReadFile(tokenPath); err == nil {
		authToken = strings.TrimSpace(string(data))
	}

	return &SessionManager{
		workloadManagerURL: workloadManagerURL,
		authToken:          authToken,
		httpClient:         &http.Client{Timeout: 30 * time.Second},
		store:              store.Storage(),
	}, nil
}

func NewJWTManager() (*JWTManager, error) {
	privateKey, err := rsa.GenerateKey(rand.Reader, 2048)
	if err != nil {
		return nil, err
	}

	return &JWTManager{
		privateKey: privateKey,
		publicKey:  &privateKey.PublicKey,
	}, nil
}

func (s *Server) setupRoutes() {
	s.router.GET("/health/live", s.handleHealthLive)
	s.router.GET("/health/ready", s.handleHealthReady)

	v1 := s.router.Group("/v1")
	v1.Use(s.concurrencyMiddleware())
	v1.Any("/namespaces/:namespace/agent-runtimes/:name/invocations/*path", s.handleInvoke(types.AgentRuntimeKind))
	v1.Any("/namespaces/:namespace/code-interpreters/:name/invocations/*path", s.handleInvoke(types.CodeInterpreterKind))
}

func (s *Server) concurrencyMiddleware() gin.HandlerFunc {
	return func(c *gin.Context) {
		select {
		case s.semaphore <- struct{}{}:
			defer func() { <-s.semaphore }()
			c.Next()
		default:
			c.JSON(http.StatusTooManyRequests, gin.H{
				"error": "server overloaded, please try again later",
				"code":  "SERVER_OVERLOADED",
			})
			c.Abort()
		}
	}
}

func (s *Server) handleHealthLive(c *gin.Context) {
	c.JSON(http.StatusOK, gin.H{"status": "alive"})
}

func (s *Server) handleHealthReady(c *gin.Context) {
	if s.sessionManager == nil {
		c.JSON(http.StatusServiceUnavailable, gin.H{
			"status": "not ready",
			"error":  "session manager not available",
		})
		return
	}
	c.JSON(http.StatusOK, gin.H{"status": "ready"})
}

func (s *Server) handleInvoke(kind string) gin.HandlerFunc {
	return func(c *gin.Context) {
		namespace := c.Param("namespace")
		name := c.Param("name")
		path := c.Param("path")

		sessionID := c.GetHeader(SessionHeader)

		sandbox, err := s.sessionManager.GetOrCreateSandbox(c.Request.Context(), sessionID, name, namespace, kind)
		if err != nil {
			s.handleError(c, err)
			return
		}

		_ = s.sessionManager.store.UpdateSessionLastActivity(c.Request.Context(), sandbox.SessionID, time.Now())

		if len(sandbox.EntryPoints) == 0 {
			c.JSON(http.StatusNotFound, gin.H{"error": "no entry point found for sandbox"})
			return
		}

		entryPoint := s.selectEntryPoint(sandbox.EntryPoints, path)
		if entryPoint == nil {
			c.JSON(http.StatusNotFound, gin.H{"error": "no entry point found for sandbox"})
			return
		}

		s.forwardToSandbox(c, sandbox, entryPoint, path)
	}
}

func (s *SessionManager) GetOrCreateSandbox(ctx context.Context, sessionID, name, namespace, kind string) (*types.SandboxInfo, error) {
	if sessionID != "" {
		sandbox, err := s.store.GetSandboxBySessionID(ctx, sessionID)
		if err == nil {
			return sandbox, nil
		}
		if !errors.Is(err, store.ErrNotFound) {
			return nil, err
		}
		return nil, &SessionNotFoundError{SessionID: sessionID}
	}

	return s.createSandbox(ctx, name, namespace, kind)
}

func (s *SessionManager) createSandbox(ctx context.Context, name, namespace, kind string) (*types.SandboxInfo, error) {
	reqBody := map[string]string{
		"kind":      kind,
		"name":      name,
		"namespace": namespace,
	}

	url := fmt.Sprintf("%s/v1/%s", s.workloadManagerURL, strings.ToLower(kind))
	if kind == types.AgentRuntimeKind {
		url = fmt.Sprintf("%s/v1/agent-runtime", s.workloadManagerURL)
	} else {
		url = fmt.Sprintf("%s/v1/code-interpreter", s.workloadManagerURL)
	}

	httpReq, err := http.NewRequestWithContext(ctx, http.MethodPost, url, nil)
	if err != nil {
		return nil, err
	}

	if s.authToken != "" {
		httpReq.Header.Set("Authorization", "Bearer "+s.authToken)
	}
	httpReq.Header.Set("Content-Type", "application/json")

	// TODO: Implement actual HTTP call with JSON body

	return &types.SandboxInfo{
		SessionID: "generated-session-id",
		Name:      name,
		EntryPoints: []types.SandboxEntryPoint{
			{Path: "/", Protocol: "HTTP", Endpoint: "localhost:8080"},
		},
	}, nil
}

func (s *Server) selectEntryPoint(entryPoints []types.SandboxEntryPoint, path string) *types.SandboxEntryPoint {
	for i := range entryPoints {
		if strings.HasPrefix(path, entryPoints[i].Path) {
			return &entryPoints[i]
		}
	}
	if len(entryPoints) > 0 {
		return &entryPoints[0]
	}
	return nil
}

func (s *Server) forwardToSandbox(c *gin.Context, sandbox *types.SandboxInfo, entryPoint *types.SandboxEntryPoint, path string) {
	targetURL := s.buildTargetURL(entryPoint)

	proxy := httputil.NewSingleHostReverseProxy(targetURL)
	proxy.Transport = s.transport

	proxy.Director = func(req *http.Request) {
		req.URL.Scheme = targetURL.Scheme
		req.URL.Host = targetURL.Host
		req.URL.Path = path
		if req.URL.Path != "" && !strings.HasPrefix(req.URL.Path, "/") {
			req.URL.Path = "/" + req.URL.Path
		}
		req.Host = targetURL.Host

		req.Header.Set("X-Forwarded-Host", c.Request.Host)
		proto := "http"
		if c.Request.TLS != nil {
			proto = "https"
		}
		req.Header.Set("X-Forwarded-Proto", proto)
		req.Header.Set("X-Forwarded-For", c.ClientIP())

		if sandbox.Kind == types.SandboxKind || sandbox.Kind == types.SandboxClaimsKind {
			token, err := s.jwtManager.GenerateToken(sandbox.SessionID)
			if err != nil {
				c.JSON(http.StatusInternalServerError, gin.H{
					"code":  "JWT_SIGNING_FAILED",
					"error": "failed to sign request",
				})
				c.Abort()
				return
			}
			req.Header.Set("Authorization", "Bearer "+token)
		}
	}

	proxy.ErrorHandler = func(w http.ResponseWriter, r *http.Request, err error) {
		if strings.Contains(err.Error(), "connection refused") {
			w.WriteHeader(http.StatusBadGateway)
			w.Write([]byte(`{"error":"sandbox unreachable"}`))
		} else if strings.Contains(err.Error(), "timeout") {
			w.WriteHeader(http.StatusGatewayTimeout)
			w.Write([]byte(`{"error":"sandbox timeout"}`))
		} else {
			w.WriteHeader(http.StatusBadGateway)
			w.Write([]byte(`{"error":"sandbox unreachable"}`))
		}
	}

	c.Header(SessionHeader, sandbox.SessionID)
	proxy.ServeHTTP(c.Writer, c.Request)

	_ = s.sessionManager.store.UpdateSessionLastActivity(c.Request.Context(), sandbox.SessionID, time.Now())
}

func (s *Server) buildTargetURL(entryPoint *types.SandboxEntryPoint) *url.URL {
	endpoint := entryPoint.Endpoint
	protocol := strings.ToLower(entryPoint.Protocol)

	if !strings.Contains(endpoint, "://") {
		endpoint = protocol + "://" + endpoint
	}

	u, _ := url.Parse(endpoint)
	return u
}

func (s *Server) handleError(c *gin.Context, err error) {
	var sessionErr *SessionNotFoundError
	if errors.As(err, &sessionErr) {
		c.JSON(http.StatusNotFound, gin.H{"error": err.Error()})
		return
	}
	c.JSON(http.StatusInternalServerError, gin.H{"error": "internal server error"})
}

func (j *JWTManager) GenerateToken(sessionID string) (string, error) {
	j.mu.RLock()
	defer j.mu.RUnlock()

	claims := jwt.MapClaims{
		"session_id": sessionID,
		"exp":        time.Now().Add(15 * time.Minute).Unix(),
		"iat":        time.Now().Unix(),
	}

	token := jwt.NewWithClaims(jwt.SigningMethodRS256, claims)
	return token.SignedString(j.privateKey)
}

func (j *JWTManager) GetPublicKeyPEM() (string, error) {
	j.mu.RLock()
	defer j.mu.RUnlock()

	if j.publicKey == nil {
		return "", errors.New("public key not available")
	}

	der, err := x509.MarshalPKIXPublicKey(j.publicKey)
	if err != nil {
		return "", err
	}

	block := &pem.Block{
		Type:  "PUBLIC KEY",
		Bytes: der,
	}

	return string(pem.EncodeToMemory(block)), nil
}

func (j *JWTManager) GetPrivateKeyPEM() (string, error) {
	j.mu.RLock()
	defer j.mu.RUnlock()

	if j.privateKey == nil {
		return "", errors.New("private key not available")
	}

	der := x509.MarshalPKCS1PrivateKey(j.privateKey)
	block := &pem.Block{
		Type:  "RSA PRIVATE KEY",
		Bytes: der,
	}

	return string(pem.EncodeToMemory(block)), nil
}

type SessionNotFoundError struct {
	SessionID string
}

func (e *SessionNotFoundError) Error() string {
	return fmt.Sprintf("session %q not found", e.SessionID)
}

func (s *Server) Start(ctx context.Context) error {
	addr := ":" + s.config.Port
	s.httpServer = &http.Server{
		Addr:        addr,
		Handler:     s.router,
		ReadTimeout: 30 * time.Second,
		IdleTimeout: 90 * time.Second,
	}

	if s.config.EnableTLS {
		if s.config.TLSCert == "" || s.config.TLSKey == "" {
			return errors.New("TLS enabled but cert/key not provided")
		}
		return s.httpServer.ListenAndServeTLS(s.config.TLSCert, s.config.TLSKey)
	}

	return s.httpServer.ListenAndServe()
}

func (s *Server) Shutdown(ctx context.Context) error {
	if s.httpServer != nil {
		ctx, cancel := context.WithTimeout(ctx, 10*time.Second)
		defer cancel()
		return s.httpServer.Shutdown(ctx)
	}
	return nil
}

