func (s *Server) forwardToSandbox(c *gin.Context, sandbox *types.SandboxInfo, entryPoint *types.SandboxEntryPoint, path string) {
	targetURL := s.buildTargetURL(entryPoint)

	proxy := httputil.NewSingleHostReverseProxy(targetURL)
	proxy.Transport = s.transport

	proxy.Director = func(req *http.Request) {
		req.URL.Scheme = targetURL.Scheme
		req.URL.Host = targetURL.Host
		req.URL.Path = path
		if req.URL.Path != "" && !strings.HasPrefix(req.URL.Path, "/") {
			req.URL.Path = "/" + req.URL.Path
		}
		req.Host = targetURL.Host

		req.Header.Set("X-Forwarded-Host", c.Request.Host)
		proto := "http"
		if c.Request.TLS != nil {
			proto = "https"
		}
		req.Header.Set("X-Forwarded-Proto", proto)
		req.Header.Set("X-Forwarded-For", c.ClientIP())

		if sandbox.Kind == types.SandboxKind || sandbox.Kind == types.SandboxClaimsKind {
			token, err := s.jwtManager.GenerateToken(sandbox.SessionID)
			if err != nil {
