	c.Header(SessionHeader, sandbox.SessionID)
	proxy.ServeHTTP(c.Writer, c.Request)

	_ = s.sessionManager.store.UpdateSessionLastActivity(c.Request.Context(), sandbox.SessionID, time.Now())
}

func (s *Server) buildTargetURL(entryPoint *types.SandboxEntryPoint) *url.URL {
	endpoint := entryPoint.Endpoint
	protocol := strings.ToLower(entryPoint.Protocol)

	if !strings.Contains(endpoint, "://") {
		endpoint = protocol + "://" + endpoint
	}

	u, _ := url.Parse(endpoint)
	return u
}

func (s *Server) handleError(c *gin.Context, err error) {
	var sessionErr *SessionNotFoundError
	if errors.As(err, &sessionErr) {
		c.JSON(http.StatusNotFound, gin.H{"error": err.Error()})
		return
	}
	c.JSON(http.StatusInternalServerError, gin.H{"error": "internal server error"})
}

func (j *JWTManager) GenerateToken(sessionID string) (string, error) {
	j.mu.RLock()
	defer j.mu.RUnlock()

	claims := jwt.MapClaims{
		"session_id": sessionID,
		"exp":        time.Now().Add(15 * time.Minute).Unix(),
		"iat":        time.Now().Unix(),
	}

	token := jwt.NewWithClaims(jwt.SigningMethodRS256, claims)
	return token.SignedString(j.privateKey)
}

func (j *JWTManager) GetPublicKeyPEM() (string, error) {
	j.mu.RLock()
	defer j.mu.RUnlock()

	if j.publicKey == nil {
		return "", errors.New("public key not available")
	}

	der, err := x509.MarshalPKIXPublicKey(j.publicKey)
	if err != nil {
		return "", err
	}

	block := &pem.Block{
		Type:  "PUBLIC KEY",
		Bytes: der,
	}

	return string(pem.EncodeToMemory(block)), nil
}

func (j *JWTManager) GetPrivateKeyPEM() (string, error) {
	j.mu.RLock()
	defer j.mu.RUnlock()

	if j.privateKey == nil {
		return "", errors.New("private key not available")
	}

	der := x509.MarshalPKCS1PrivateKey(j.privateKey)
	block := &pem.Block{
		Type:  "RSA PRIVATE KEY",
		Bytes: der,
	}

	return string(pem.EncodeToMemory(block)), nil
}

type SessionNotFoundError struct {
	SessionID string
}

func (e *SessionNotFoundError) Error() string {
	return fmt.Sprintf("session %q not found", e.SessionID)
}

func (s *Server) Start(ctx context.Context) error {
	addr := ":" + s.config.Port
	s.httpServer = &http.Server{
		Addr:        addr,
		Handler:     s.router,
		ReadTimeout: 30 * time.Second,
		IdleTimeout: 90 * time.Second,
	}

	if s.config.EnableTLS {
		if s.config.TLSCert == "" || s.config.TLSKey == "" {
			return errors.New("TLS enabled but cert/key not provided")
		}
		return s.httpServer.ListenAndServeTLS(s.config.TLSCert, s.config.TLSKey)
	}

	return s.httpServer.ListenAndServe()
}

func (s *Server) Shutdown(ctx context.Context) error {
	if s.httpServer != nil {
		ctx, cancel := context.WithTimeout(ctx, 10*time.Second)
		defer cancel()
		return s.httpServer.Shutdown(ctx)
	}
	return nil
}

