package agentd

import (
	"context"
	"time"

	metav1 "k8s.io/apimachinery/pkg/apis/meta/v1"
	"k8s.io/apimachinery/pkg/runtime"
	ctrl "sigs.k8s.io/controller-runtime"
	"sigs.k8s.io/controller-runtime/pkg/client"
	sandboxv1alpha1 "sigs.k8s.io/agent-sandbox/api/v1alpha1"
)

const (
	LastActivityAnnotationKey = "last-activity-time"
	SessionExpirationTimeout  = 15 * time.Minute
)

type SandboxReconciler struct {
	client.Client
	Scheme *runtime.Scheme
}

func (r *SandboxReconciler) Reconcile(ctx context.Context, req ctrl.Request) (ctrl.Result, error) {
	var sandbox sandboxv1alpha1.Sandbox
	if err := r.Get(ctx, req.NamespacedName, &sandbox); err != nil {
		return ctrl.Result{}, client.IgnoreNotFound(err)
	}

	lastActivityAnnotation := sandbox.Annotations[LastActivityAnnotationKey]
	if lastActivityAnnotation == "" {
		return ctrl.Result{}, nil
	}

	lastActivity, err := time.Parse(time.RFC3339, lastActivityAnnotation)
	if err != nil {
		return ctrl.Result{RequeueAfter: 30 * time.Second}, err
	}

	expirationTime := lastActivity.Add(SessionExpirationTimeout)
	if time.Now().After(expirationTime) {
		if err := r.Delete(ctx, &sandbox); err != nil {
			return ctrl.Result{}, client.IgnoreNotFound(err)
		}
		return ctrl.Result{}, nil
	}

	return ctrl.Result{RequeueAfter: time.Until(expirationTime)}, nil
}

func SetupReconciler(mgr ctrl.Manager) error {
	return ctrl.NewControllerManagedBy(mgr).
		For(&sandboxv1alpha1.Sandbox{}).
		Complete(&SandboxReconciler{
			Client: mgr.GetClient(),
			Scheme: mgr.GetScheme(),
		})
}

package main

import (
	"context"
	"flag"
	"fmt"
	"os"
	"os/signal"
	"syscall"

	corev1 "k8s.io/api/core/v1"
	"k8s.io/apimachinery/pkg/runtime"
	utilruntime "k8s.io/apimachinery/pkg/util/runtime"
	clientgoscheme "k8s.io/client-go/kubernetes/scheme"
	ctrl "sigs.k8s.io/controller-runtime"
	sandboxv1alpha1 "sigs.k8s.io/agent-sandbox/api/v1alpha1"

	"github.com/volcano-sh/agentcube/pkg/agentd"
)

var scheme = runtime.NewScheme()

func init() {
	utilruntime.Must(clientgoscheme.AddToScheme(scheme))
	utilruntime.Must(corev1.AddToScheme(scheme))
	utilruntime.Must(sandboxv1alpha1.AddToScheme(scheme))
}

func main() {
	metricsAddr := flag.String("metrics-addr", "0", "Metrics server address")
	healthAddr := flag.String("health-addr", "0", "Health probe server address")
	flag.Parse()

	mgr, err := ctrl.NewManager(ctrl.GetConfigOrDie(), ctrl.Options{
		Scheme:                     scheme,
		Metrics:                    ctrl.MetricsOptions{BindAddress: *metricsAddr},
		HealthProbeBindAddress:     *healthAddr,
	})
	if err != nil {
		fmt.Fprintf(os.Stderr, "Failed to create manager: %v\n", err)
		os.Exit(1)
	}

	if err := agentd.SetupReconciler(mgr); err != nil {
		fmt.Fprintf(os.Stderr, "Failed to setup reconciler: %v\n", err)
		os.Exit(1)
	}

	ctx, cancel := signal.NotifyContext(context.Background(), syscall.SIGINT, syscall.SIGTERM)
	defer cancel()

	fmt.Println("Starting agentd controller")
	if err := mgr.Start(ctrl.SetupSignalHandler()); err != nil {
		fmt.Fprintf(os.Stderr, "Manager error: %v\n", err)
		os.Exit(1)
	}
}

