package store

import (
	"context"
	"encoding/json"
	"errors"
	"fmt"
	"os"
	"strconv"
	"strings"
	"time"

	"github.com/valkey-io/valkey-go"
	"github.com/volcano-sh/agentcube/pkg/common/types"
)

type valkeyStore struct {
	cli                  valkey.Client
	sessionPrefix        string
	expiryIndexKey       string
	lastActivityIndexKey string
}

func newValkeyStore() (*valkeyStore, error) {
	valkeyAddr := os.Getenv("VALKEY_ADDR")
	if valkeyAddr == "" {
		return nil, errors.New("VALKEY_ADDR is required")
	}

	valkeyPassword := os.Getenv("VALKEY_PASSWORD")
	passwordRequired := os.Getenv("VALKEY_PASSWORD_REQUIRED")
	if valkeyPassword == "" && !stringsEqualIgnoreCase(passwordRequired, "false") {
		return nil, errors.New("VALKEY_PASSWORD is required")
	}

	opts := valkey.ClientOption{
		InitAddress: strings.Split(valkeyAddr, ","),
		Password:    valkeyPassword,
	}

	if v := os.Getenv("VALKEY_DISABLE_CACHE"); stringsEqualIgnoreCase(v, "true") {
		opts.DisableCache = true
	}
	if v := os.Getenv("VALKEY_FORCE_SINGLE"); stringsEqualIgnoreCase(v, "true") {
		opts.ForceSingleClient = true
	}

	cli, err := valkey.NewClient(opts)
	if err != nil {
		return nil, err
	}

	return &valkeyStore{
		cli:                  cli,
		sessionPrefix:        "session:",
		expiryIndexKey:       "session:expiry",
		lastActivityIndexKey: "session:last_activity",
	}, nil
}

func (s *valkeyStore) Ping(ctx context.Context) error {
	resp := s.cli.Do(ctx, s.cli.B().Ping().Build())
	result, err := resp.ToString()
	if err != nil {
		return err
	}
	if result != "PONG" {
		return fmt.Errorf("unexpected ping response: %s", result)
	}
	return nil
}

func (s *valkeyStore) sessionKey(sessionID string) string {
	return s.sessionPrefix + sessionID
}

func (s *valkeyStore) GetSandboxBySessionID(ctx context.Context, sessionID string) (*types.SandboxInfo, error) {
	key := s.sessionKey(sessionID)
	resp := s.cli.Do(ctx, s.cli.B().Get().Key(key).Build())
	data, err := resp.AsBytes()
	if err != nil {
		if valkey.IsValkeyNil(err) {
			return nil, ErrNotFound
		}
		return nil, err
	}
	var info types.SandboxInfo
	if err := json.Unmarshal(data, &info); err != nil {
		return nil, err
	}
	return &info, nil
}

func (s *valkeyStore) StoreSandbox(ctx context.Context, sandboxStore *types.SandboxInfo) error {
	if sandboxStore == nil {
		return errors.New("sandbox is nil")
	}
	if sandboxStore.ExpiresAt.IsZero() {
		return errors.New("ExpiresAt is required")
	}

	key := s.sessionKey(sandboxStore.SessionID)
	data, err := json.Marshal(sandboxStore)
	if err != nil {
		return err
	}

	cmds := []valkey.Completed{
		s.cli.B().Setnx().Key(key).Value(string(data)).Build(),
		s.cli.B().Zadd().Key(s.expiryIndexKey).ScoreMember().ScoreMember(float64(sandboxStore.ExpiresAt.Unix()), sandboxStore.SessionID).Build(),
		s.cli.B().Zadd().Key(s.lastActivityIndexKey).ScoreMember().ScoreMember(float64(time.Now().Unix()), sandboxStore.SessionID).Build(),
	}

	return s.cli.DoMulti(ctx, cmds...).Error()
}

func (s *valkeyStore) UpdateSandbox(ctx context.Context, sandboxStore *types.SandboxInfo) error {
	key := s.sessionKey(sandboxStore.SessionID)
	data, err := json.Marshal(sandboxStore)
	if err != nil {
		return err
	}

	resp := s.cli.Do(ctx, s.cli.B().Set().Key(key).Value(string(data)).Xx().Build())
	result, err := resp.ToString()
	if err != nil {
		return err
	}
	if result != "OK" {
		return errors.New("key not exists")
	}
	return nil
}

func (s *valkeyStore) DeleteSandboxBySessionID(ctx context.Context, sessionID string) error {
	key := s.sessionKey(sessionID)

	cmds := []valkey.Completed{
		s.cli.B().Del().Key(key).Build(),
		s.cli.B().Zrem().Key(s.expiryIndexKey).Member(sessionID).Build(),
		s.cli.B().Zrem().Key(s.lastActivityIndexKey).Member(sessionID).Build(),
	}

	return s.cli.DoMulti(ctx, cmds...).Error()
}

func (s *valkeyStore) ListExpiredSandboxes(ctx context.Context, before time.Time, limit int64) ([]*types.SandboxInfo, error) {
	if limit <= 0 {
		return nil, nil
	}

	resp := s.cli.Do(ctx, s.cli.B().Zrangebyscore().Key(s.expiryIndexKey).
		Min("-inf").Max(strconv.FormatInt(before.Unix(), 10)).
		Limit(0, limit).Build())

	sessionIDs, err := resp.AsStrSlice()
	if err != nil {
		return nil, err
	}

