	resp := s.cli.Do(ctx, s.cli.B().Zrangebyscore().Key(s.expiryIndexKey).
		Min("-inf").Max(strconv.FormatInt(before.Unix(), 10)).
		Limit(0, limit).Build())

	sessionIDs, err := resp.AsStrSlice()
	if err != nil {
		return nil, err
	}

	return s.loadSandboxesBySessionIDs(ctx, sessionIDs)
}

func (s *valkeyStore) ListInactiveSandboxes(ctx context.Context, before time.Time, limit int64) ([]*types.SandboxInfo, error) {
	if limit <= 0 {
		return nil, nil
	}

	resp := s.cli.Do(ctx, s.cli.B().Zrangebyscore().Key(s.lastActivityIndexKey).
		Min("-inf").Max(strconv.FormatInt(before.Unix(), 10)).
		Limit(0, limit).Build())

	sessionIDs, err := resp.AsStrSlice()
	if err != nil {
		return nil, err
	}

	return s.loadSandboxesBySessionIDs(ctx, sessionIDs)
}

func (s *valkeyStore) loadSandboxesBySessionIDs(ctx context.Context, sessionIDs []string) ([]*types.SandboxInfo, error) {
	if len(sessionIDs) == 0 {
		return nil, nil
	}

	keys := make([]string, len(sessionIDs))
	for i, id := range sessionIDs {
		keys[i] = s.sessionKey(id)
	}

	resp := s.cli.Do(ctx, s.cli.B().Mget().Key(keys...).Build())
	results, err := resp.AsStrSlice()
	if err != nil {
		return nil, err
	}

	var sandboxes []*types.SandboxInfo
	for i, result := range results {
		if result == "" {
			continue
		}
		var info types.SandboxInfo
		if err := json.Unmarshal([]byte(result), &info); err != nil {
			continue
		}
		sandboxes = append(sandboxes, &info)
		_ = i
	}

	return sandboxes, nil
}

func (s *valkeyStore) UpdateSessionLastActivity(ctx context.Context, sessionID string, at time.Time) error {
	if sessionID == "" {
		return errors.New("session id is empty")
	}

	key := s.sessionKey(sessionID)
	resp := s.cli.Do(ctx, s.cli.B().Exists().Key(key).Build())
	exists, err := resp.AsInt64()
	if err != nil {
		return err
	}
	if exists == 0 {
		return ErrNotFound
	}

	if at.IsZero() {
		at = time.Now()
	}

	return s.cli.Do(ctx, s.cli.B().Zadd().Key(s.lastActivityIndexKey).
		ScoreMember().ScoreMember(float64(at.Unix()), sessionID).Build()).Error()
}

func (s *valkeyStore) Close() error {
	s.cli.Close()
	return nil
}

