)

type Config struct {
	Port             string
	RuntimeClassName string
	EnableTLS        bool
	TLSCert          string
	TLSKey           string
	EnableAuth       bool
}

type Server struct {
	config            *Config
	router            *gin.Engine
	httpServer        *http.Server
	k8sClient         *K8sClient
