	informers         *Informers
	storeClient       store.Store
	wg                sync.WaitGroup
}

func NewServer(cfg *Config) (*Server, error) {
	gin.SetMode(gin.ReleaseMode)
	r := gin.New()
	r.Use(gin.Logger(), gin.Recovery())

	s := &Server{
		config:      cfg,
		router:      r,
		storeClient: store.Storage(),
		tokenCache:  NewTokenCache(1000, 5*time.Minute),
	}

	if err := s.setupRoutes(); err != nil {
		return nil, err
	}

	return s, nil
}

func (s *Server) setupRoutes() error {
	s.router.GET("/health", s.handleHealth)

	v1 := s.router.Group("/v1")
	v1.Use(loggingMiddleware())
	if s.config.EnableAuth {
		v1.Use(s.authMiddleware())
	}

	v1.POST("/agent-runtime", s.handleAgentRuntimeCreate)
	v1.DELETE("/agent-runtime/sessions/:sessionId", s.handleDeleteSandbox)
	v1.POST("/code-interpreter", s.handleCodeInterpreterCreate)
	v1.DELETE("/code-interpreter/sessions/:sessionId", s.handleDeleteSandbox)

	return nil
}

func loggingMiddleware() gin.HandlerFunc {
	return func(c *gin.Context) {
		start := time.Now()
		c.Next()
		duration := time.Since(start)
		c.Writer.Header().Set("X-Response-Time", duration.String())
	}
}

func (s *Server) handleHealth(c *gin.Context) {
	c.JSON(http.StatusOK, gin.H{"status": "healthy"})
}

func (s *Server) Start(ctx context.Context) error {
	addr := ":" + s.config.Port
	s.httpServer = &http.Server{
		Addr:        addr,
		Handler:     s.router,
		ReadTimeout: 15 * time.Second,
		IdleTimeout: 90 * time.Second,
	}

	if s.config.EnableTLS {
		if s.config.TLSCert == "" || s.config.TLSKey == "" {
			return errorf("TLS enabled but cert/key not provided")
		}
		return s.httpServer.ListenAndServeTLS(s.config.TLSCert, s.config.TLSKey)
	}

	return s.httpServer.ListenAndServe()
}

func (s *Server) Shutdown(ctx context.Context) error {
	ctx, cancel := context.WithTimeout(ctx, 15*time.Second)
	defer cancel()
	return s.httpServer.Shutdown(ctx)
}

func errorf(msg string) error {
	return &serverError{msg: msg}
}

type serverError struct {
	msg string
}

func (e *serverError) Error() string {
	return e.msg
}

